import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { booksAPI } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import BookFormModal from '../components/BookFormModal';
import { useCart } from '../context/CartContext';
import ReviewSection from '../components/ReviewSection';   // ✅ NEW
import './BookDetail.css';

const CATEGORY_COLORS = {
  Fiction: '#c9a84c', 'Non-Fiction': '#4caf82', Science: '#5b8dee',
  History: '#c47c5a', Technology: '#9b72cf', Romance: '#d4709a',
  Mystery: '#7a9e9f',
};

export default function BookDetail() {
  const { id }     = useParams();
  const [book, setBook]           = useState(null);
  const [loading, setLoading]     = useState(true);
  const [showEdit, setShowEdit]   = useState(false);
  const [addingToCart, setAddingToCart] = useState(false);
  const { isAdmin } = useAuth();
  const toast       = useToast();
  const navigate    = useNavigate();
  const { addItem, isInCart } = useCart();

  useEffect(() => {
    (async () => {
      setLoading(true);
      try {
        const res = await booksAPI.getById(id);
        setBook(res.data);
      } catch {
        toast.error('Book not found');
        navigate('/books');
      } finally {
        setLoading(false);
      }
    })();
  }, [id]);

  const handleDelete = async () => {
    if (!window.confirm('Delete this book permanently?')) return;
    try {
      await booksAPI.delete(id);
      toast.success('Book deleted');
      navigate('/books');
    } catch {
      toast.error('Delete failed');
    }
  };

  const handleEditSave = async (data) => {
    try {
      const res = await booksAPI.update(id, data);
      setBook(res.data);
      toast.success('Book updated');
      setShowEdit(false);
    } catch {
      toast.error('Update failed');
    }
  };

  const handleAddToCart = async () => {
    setAddingToCart(true);
    try {
      await addItem(book, 1);
      toast.success(`"${book.title}" added to cart!`);
    } catch {
      toast.error('Failed to add to cart. Please login first.');
    } finally {
      setAddingToCart(false);
    }
  };

  if (loading) return <div className="loading-wrap"><div className="spinner" /></div>;
  if (!book)   return null;

  const color   = CATEGORY_COLORS[book.category] || '#c9a84c';
  const initial = (book.title || 'B')[0].toUpperCase();

  return (
    <div className="book-detail-page">
      <div className="container">

        {/* Breadcrumb */}
        <div className="breadcrumb fade-up">
          <Link to="/books">← Back to Catalog</Link>
        </div>

        <div className="book-detail-layout fade-up">
          {/* Cover */}
          <div className="detail-cover" style={{ '--accent': color }}>
            <div className="detail-spine" style={{ background: color }} />
            <div className="detail-initial">{initial}</div>
            <div className="detail-category">{book.category || 'General'}</div>
          </div>

          {/* Info */}
          <div className="detail-info">
            <h1 className="detail-title">{book.title}</h1>
            <p className="detail-author">by <em>{book.author}</em></p>

            <div className="divider" />

            <div className="detail-stats">
              <div className="stat">
                <span className="stat-label">Price</span>
                <span className="stat-value text-gold">₹{book.price?.toFixed(2)}</span>
              </div>
              <div className="stat">
                <span className="stat-label">Stock</span>
                <span
                  className="stat-value"
                  style={{ color: book.stock > 0 ? 'var(--green)' : 'var(--red)' }}
                >
                  {book.stock > 0 ? `${book.stock} available` : 'Out of stock'}
                </span>
              </div>
              <div className="stat">
                <span className="stat-label">Category</span>
                <span className="stat-value">{book.category || '—'}</span>
              </div>
              <div className="stat">
                <span className="stat-label">Book ID</span>
                <span className="stat-value text-dim">#{book.id}</span>
              </div>
            </div>

            <div className="divider" />

            {/* Status badge */}
            <div style={{ marginBottom: 'var(--gap-lg)' }}>
              {book.stock > 0 ? (
                <span className="badge badge-green">✓ In Stock</span>
              ) : (
                <span className="badge badge-red">✕ Out of Stock</span>
              )}
            </div>

            {/* Admin actions */}
            {isAdmin() && (
              <div className="detail-actions">
                <button className="btn btn-outline" onClick={() => setShowEdit(true)}>
                  ✏️ Edit Book
                </button>
                <button className="btn btn-danger" onClick={handleDelete}>
                  🗑️ Delete Book
                </button>
              </div>
            )}

            {/* Add to Cart */}
            {!isAdmin() && book.stock > 0 && (
              <div className="detail-actions">
                <button
                  className={`btn ${isInCart(book.id) ? 'btn-outline' : 'btn-gold'}`}
                  onClick={handleAddToCart}
                  disabled={addingToCart}
                >
                  {addingToCart
                    ? 'Adding…'
                    : isInCart(book.id)
                    ? '✓ In Cart'
                    : '🛒 Add to Cart'}
                </button>
                <Link to="/cart" className="btn btn-ghost">
                  View Cart →
                </Link>
              </div>
            )}

            {!isAdmin() && book.stock === 0 && (
              <span className="badge badge-red" style={{ fontSize: 13, padding: '6px 14px' }}>
                ✕ Out of Stock — Cannot add to cart
              </span>
            )}
          </div>
        </div>

        {/* ✅ Reviews section — always shown below the book info */}
        <ReviewSection bookId={book.id} />

      </div>

      {showEdit && (
        <BookFormModal
          book={book}
          onSave={handleEditSave}
          onClose={() => setShowEdit(false)}
        />
      )}
    </div>
  );
}
